import type { Point } from '../../../../../../../types/point.js';
import { getShapeLinesBisect } from '../../../../../../../utils/get-shape-lines-bisect.js';
import { buildMarkerOrientationStrategy } from '../build-marker-orientation-strategy.js';
import type { ValueMarkerPointerPosition } from '../types.js';

export const getMarkerGeometry = (
  orientation: ValueMarkerPointerPosition,
  x: number,
  y: number,
  width: number,
) => {
  const valueMarkerBuilder = buildMarkerOrientationStrategy[orientation];
  const markerVertexes = valueMarkerBuilder(x, y, width);
  const markerLinesBisect = getShapeLinesBisect(markerVertexes);

  const markerGeometry: Point[] = [];

  for (let i = 0; i < markerVertexes.length; i++) {
    markerGeometry.push(markerVertexes[i]);
    markerGeometry.push(markerLinesBisect[i]);
  }

  // We need to close the path rounding the initial point as well.
  markerGeometry.push(markerVertexes[0]);
  markerGeometry.push(markerLinesBisect[0]);

  return markerGeometry;
};
